static const unsigned int kPdfOneAttach_len = 759;

class PopplerDocumentGetNAttachmentsTest_2154 : public ::testing::Test {
protected:
  static PopplerDocument* NewDocFromDataOrNull(const unsigned char* data,
                                              unsigned int len) {
    GError* error = nullptr;
    PopplerDocument* doc = poppler_document_new_from_data(
        reinterpret_cast<const char*>(data),
        static_cast<int>(len),
        /*password=*/nullptr,
        &error);
    if (error) {
      g_error_free(error);
      error = nullptr;
    }
    return doc;
  }
};

TEST_F(PopplerDocumentGetNAttachmentsTest_2154, NullDocumentReturnsZero_2154) {
  EXPECT_EQ(0u, poppler_document_get_n_attachments(nullptr));
}

TEST_F(PopplerDocumentGetNAttachmentsTest_2154,
       NonDocumentPointerReturnsZero_2154) {
  // Pass a valid GObject that is NOT a PopplerDocument instance.
  GObject* obj = G_OBJECT(g_object_new(G_TYPE_OBJECT, nullptr));
  ASSERT_NE(nullptr, obj);

  EXPECT_EQ(0u, poppler_document_get_n_attachments(
                    reinterpret_cast<PopplerDocument*>(obj)));

  g_object_unref(obj);
}

TEST_F(PopplerDocumentGetNAttachmentsTest_2154,
       ValidDocumentWithoutAttachmentsReturnsZero_2154) {
  PopplerDocument* doc = NewDocFromDataOrNull(kPdfNoAttach, kPdfNoAttach_len);
  ASSERT_NE(nullptr, doc);

  EXPECT_EQ(0u, poppler_document_get_n_attachments(doc));
  // Idempotency / stability for repeated calls (observable behavior).
  EXPECT_EQ(0u, poppler_document_get_n_attachments(doc));

  g_object_unref(doc);
}

TEST_F(PopplerDocumentGetNAttachmentsTest_2154,
       ValidDocumentWithOneAttachmentReturnsNonZero_2154) {
  PopplerDocument* doc = NewDocFromDataOrNull(kPdfOneAttach, kPdfOneAttach_len);
  ASSERT_NE(nullptr, doc);

  const guint n = poppler_document_get_n_attachments(doc);
  EXPECT_GE(n, 1u);
  // For this crafted PDF, we expect exactly one embedded file entry.
  EXPECT_EQ(1u, n);

  // Repeated call should match (observable, no internal peeking).
  EXPECT_EQ(1u, poppler_document_get_n_attachments(doc));

  g_object_unref(doc);
}

